import Combine
import Foundation
import FactoryKit

extension Container {

    var dataBufferRepository: Factory<DataBufferRepository> {
        self { self.dataBufferRepositoryImpl() }
    }

    var dataBufferSetupRepository: Factory<DataBufferSetupRepository> {
        self { self.dataBufferRepositoryImpl() }
    }

    private var dataBufferRepositoryImpl: Factory<DataBufferRepositoryImpl> {
        self { DataBufferRepositoryImpl() }
            .singleton
    }
}

protocol DataBufferRepository {

    var countRatePublisher: AnyPublisher<RadiationData, Never> { get }
    var rawCountRatePublisher: AnyPublisher<DataBufferBatch, Never> { get }
    var purifiedCountRatePublisher: AnyPublisher<DataBufferBatch, Never> { get }

    var doseRatePublisher: AnyPublisher<RadiationData, Never> { get }
    var rawDoseRatePublisher: AnyPublisher<DataBufferBatch, Never> { get }
    var purifiedDoseRatePublisher: AnyPublisher<DataBufferBatch, Never> { get }

    var doseCollectedSubject: CurrentValueSubject<RareDataDTO.Dose?, Never> { get }
    var indicatorSubject: PassthroughSubject<RareDataDTO.Indicator?, Never> { get }

    var eventPublisher: AnyPublisher<Event, Never> { get }

    var doseCounterPublisher: AnyPublisher<CounterBatch, Never> { get }

    var initialPurifiedCountRateSubject: PassthroughSubject<[DataBufferBatch], Never> { get }
    var initialPurifiedDoseRateSubject: PassthroughSubject<[DataBufferBatch], Never> { get }
}

protocol DataBufferSetupRepository {
    func startBufferCollect()
    func cancelBufferCollect()
}

final class DataBufferRepositoryImpl: DataBufferRepository, DataBufferSetupRepository {

    enum DataBufferRepositoryError: Error {
        case emptyFirmware
    }

    private enum Consts {
        static let minimalDate: Date = .init(timeIntervalSince1970: 1577836800) // 2020-01-01 00:00:00 UTC
    }

    private typealias UintBatchItem = BatchValue<UInt32, Int32>
    private typealias FloatBatchItem = BatchValue<Float, Int32>

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.deviceConnectionManager) private var deviceConnectionManager

    private let dataBufferDatabaseManager: DataBufferDatabaseManager = DataBufferDatabaseManagerImpl()

    // MARK: - CountRate

    var countRatePublisher: AnyPublisher<RadiationData, Never> {
        Publishers.Zip(
            countRateSubject,
            countRateErrorSubject
        )
        .map { data, error in
            RadiationData(value: data.value, time: self.convertTime(data.time), error: error, level: self.countRateAlarms.checkValue(data.value))
        }
        .eraseToAnyPublisher()
    }

    var rawCountRatePublisher: AnyPublisher<DataBufferBatch, Never> { mappedPublisher(rawCountRateSubject) }
    var purifiedCountRatePublisher: AnyPublisher<DataBufferBatch, Never> { mappedPublisher(purifiedCountRateSubject) }

    // MARK: - DoseRate

    var doseRatePublisher: AnyPublisher<RadiationData, Never> {
        Publishers.Zip(
            doseRateSubject,
            doseRateErrorSubject
        )
        .map { data, error in
            RadiationData(value: data.value, time: self.convertTime(data.time), error: error, level: self.doseRateAlarms.checkValue(data.value))
        }
        .eraseToAnyPublisher()
    }

