import FactoryKit

extension Container {

    var chartModelBuilder: Factory<ChartModelBuilder> {
        self { ChartModelBuilderImpl() }
            .shared
    }

    var countRateModel: Factory<RadiationLevelViewModel> {
        self {
            let dataBufferRepository = self.dataBufferRepository()
            return RadiationLevelViewModel(
                chartModelBuilder: self.chartModelBuilder(),
                rawDataPublisher: dataBufferRepository.rawCountRatePublisher,
                purifiedDataPublisher: dataBufferRepository.purifiedCountRatePublisher,
                valuePublisher: dataBufferRepository.countRatePublisher,
                initialDataPublisher: dataBufferRepository.initialPurifiedCountRateSubject.eraseToAnyPublisher(),
                queueLabel: RadiationType.Level.countRate.rawValue
            )
        }
        .singleton
    }

    var doseRateModel: Factory<RadiationLevelViewModel> {
        self {
            let dataBufferRepository = self.dataBufferRepository()
            return RadiationLevelViewModel(
                chartModelBuilder: self.chartModelBuilder(),
                rawDataPublisher: dataBufferRepository.rawDoseRatePublisher,
                purifiedDataPublisher: dataBufferRepository.purifiedDoseRatePublisher,
                valuePublisher: dataBufferRepository.doseRatePublisher,
                initialDataPublisher: dataBufferRepository.initialPurifiedDoseRateSubject.eraseToAnyPublisher(),
                queueLabel: RadiationType.Level.doseRate.rawValue
            )
        }
        .singleton
    }

    var hardnessModel: Factory<RadiationLevelViewModel> {
        self {
            let dataBufferRepository = self.dataBufferRepository()
            let rawDataPublisher = Publishers.Zip(dataBufferRepository.rawCountRatePublisher, dataBufferRepository.rawDoseRatePublisher)
                .map { DataBufferBatch(value: $1.value.safePercent(of: $0.value), time: $0.time) }
                .eraseToAnyPublisher()

            let purifiedDataPublisher = Publishers.Zip(dataBufferRepository.purifiedCountRatePublisher, dataBufferRepository.purifiedDoseRatePublisher)
                .map { DataBufferBatch(value: $1.value.safePercent(of: $0.value), time: $0.time) }
                .eraseToAnyPublisher()

            let valueDataPublisher = Publishers.Zip(dataBufferRepository.countRatePublisher, dataBufferRepository.doseRatePublisher)
                .map { RadiationData(value: $1.value.safePercent(of: $0.value),time: $0.time, error: 0.0, level: .normal) }
                .eraseToAnyPublisher()

            let initialDataPublisher = Publishers.Zip(dataBufferRepository.initialPurifiedCountRateSubject, dataBufferRepository.initialPurifiedDoseRateSubject)
                .map { zip($0, $1).map { DataBufferBatch(value: $1.value.safePercent(of: $0.value), time: $0.time) } }
                .eraseToAnyPublisher()

            return RadiationLevelViewModel(
                chartModelBuilder: self.chartModelBuilder(),
                rawDataPublisher: rawDataPublisher,
                purifiedDataPublisher: purifiedDataPublisher,
                valuePublisher: valueDataPublisher,
                initialDataPublisher: initialDataPublisher,
                queueLabel: "Hardness"
            )
        }
        .singleton
    }
}

