    let type: RadiationType
    let data: EventRowModel.AlarmData

    var body: some View {
        HStack(spacing: 4) {
            switch type {
            case .radiationLevel(let level):
                switch level {
                case .countRate:
                    Image(.Events.Unit.s1)
                case .doseRate:
                    Image(.Events.Unit.gamma)
                }
            case .dose:
                Image(.Events.Unit.sigma)
            }
            HStack(alignment: .bottom, spacing: 2) {
                RadiationValueLabelView(value: data.value.asDecimal, radiationType: type)
                    .font(.system(size: 15))

                if let error = data.error, !error.isZero {
                    Text(verbatim: "±\(String(format: "%.0f", error))%")
                        .font(.system(size: 11))
                }
            }
            .lineLimit(1)
            .monospacedDigit()
            .padding(.horizontal, 6)
            .padding(.vertical, 4)
            .foregroundStyle(.textPrimary)
            .roundedBorder(data.alarmLevel.borderColor, radius: 8)
        }
    }
}

