import Foundation
import Combine
import FactoryKit

extension Container {

    var deviceDoseWidgetViewModel: Factory<DeviceDoseWidgetViewModel> {
        self { DeviceDoseWidgetViewModel() }
            .singleton
    }
}

@Observable
final class DeviceDoseWidgetViewModel {

    @ObservationIgnored
    @Injected(\.deviceManager) private var deviceManager

    @ObservationIgnored
    @Injected(\.dataBufferRepository) private var dataBufferRepository

    @ObservationIgnored
    @Injected(\.deviceConnectionManager) private var deviceConnectionManager

    var doseValue: Decimal?
    var alarmLevelValue: Decimal?
    var level: SignalizationAlarmLevel = .normal

    var percent: Decimal?
    var percentOfLevel: LocalizedStringResource = .Dose.lvl

    var time: String = "--:--:--"

    var deviceIsReady: Bool = false

    var supportDoseCounter: Bool = true

    @ObservationIgnored
    private var cancellable: Set<AnyCancellable> = .init()

    @ObservationIgnored
    private var doseCancellable: AnyCancellable?

    @ObservationIgnored
    private var dose: RareDataDTO.Dose?

    @ObservationIgnored
    private var doseAlarms: Alarm.Level = .init(radiationType: .dose)

    init() {
        deviceConnectionManager.connectionSubject
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self else { return }
                self.deviceIsReady = state.isReady
                guard let device = state.readyDevice else { return }
                self.subscribeAlarms(for: device)
                self.supportDoseCounter = device.supportDoseCounter
            }
            .store(in: &cancellable)

        dataBufferRepository.doseCollectedSubject
            .receive(on: DispatchQueue.main)
            .sink { [weak self] dose in
                guard let self else { return }
                self.dose = dose
                self.calculateDose()
            }
            .store(in: &cancellable)
    }

    func resetDose() {
        Task {
            await deviceManager.send(command: DoseResetCommand())
        }
    }

    func subscribeAlarms(for device: BluetoothDevice) {
        doseCancellable?.cancel()
        doseCancellable = device.alarms
            .publisher(\.dose)
            .receive(on: DispatchQueue.main)
            .removeDuplicates()
            .sink { [weak self] alarms in
                self?.doseAlarms = alarms
                self?.calculateDose()
            }
    }

    private func calculateDose() {
        guard let dose else {
            self.doseValue = nil
            self.alarmLevelValue = nil
            self.level = .normal
            self.percent = nil
            self.percentOfLevel = .Dose.lvl
            self.time = "--:--:--"
            return
        }

        let doseValue = dose.value * 10000
        let decimalDose = Decimal(Double(doseValue))

        self.doseValue = decimalDose

        let level = doseAlarms.checkValue(doseValue)

        let levelValue: (value: Decimal?, label: LocalizedStringResource) = {
            switch level {
            case .normal:
                (doseAlarms.level1, .Dose.lvl1)
            case .level1:
                (doseAlarms.level2, .Dose.lvl2)
            case .level2, .offScale:
                (doseAlarms.offScale, .Dose.offScale)
            }
        }()

        if let value = levelValue.value {
            self.alarmLevelValue = levelValue.value
            self.percent = (decimalDose / value) * 100
        }

        self.level = level
        self.percentOfLevel = levelValue.label
        self.time = UInt32(dose.duration).toFormattedString
    }
}
